+    "crates/ffs-ondisk",
+    "crates/ffs-block",
+    "crates/ffs-journal",
+    "crates/ffs-mvcc",
+    "crates/ffs-btree",
+    "crates/ffs-alloc",
+    "crates/ffs-inode",
+    "crates/ffs-dir",
+    "crates/ffs-extent",
+    "crates/ffs-xattr",
+    "crates/ffs-fuse",
+    "crates/ffs-repair",
+    "crates/ffs-core",
+    "crates/ffs",
+    "crates/ffs-cli",
+    "crates/ffs-tui",
